import { ApiClient } from "./api-client";
import type {
  ConsumerGroupOptions,
  Message,
  MessageHandler,
  MessageMetadata,
  RetryDirective,
  RetryHandler,
} from "./types";
import {
  BadRequestError,
  ForbiddenError,
  MessageNotAvailableError,
  MessageNotFoundError,
  UnauthorizedError,
} from "./types";

/**
 * Default visibility timeout in seconds (5 minutes).
 * This is the initial lock duration requested when receiving messages.
 */
const DEFAULT_VISIBILITY_TIMEOUT_SECONDS = 300;

/**
 * Minimum visibility timeout in seconds.
 * Ensures auto-extension has enough time to renew before the lease expires.
 */
const MIN_VISIBILITY_TIMEOUT_SECONDS = 30;

/**
 * Maximum renewal interval in seconds.
 * Even for very long visibility timeouts, we renew at least this often.
 */
const MAX_RENEWAL_INTERVAL_SECONDS = 60;

/**
 * Minimum renewal interval in seconds.
 * Even for very short visibility timeouts, we don't renew more frequently than this.
 */
const MIN_RENEWAL_INTERVAL_SECONDS = 10;

/**
 * Interval in milliseconds between retry attempts when extension fails.
 * On transient failures, retry every 3 seconds.
 */
const RETRY_INTERVAL_MS = 3000;

/**
 * Calculate the renewal interval based on visibility timeout.
 * Formula: min(60, max(10, visibilityTimeout / 5))
 *
 * Examples:
 * - 300s visibility → 60s interval (300/5 = 60, capped at 60)
 * - 200s visibility → 40s interval (200/5 = 40)
 * - 100s visibility → 20s interval (100/5 = 20)
 * - 30s visibility → 10s interval (30/5 = 6, floored at 10)
 */
function calculateRenewalInterval(visibilityTimeoutSeconds: number): number {
  return Math.min(
    MAX_RENEWAL_INTERVAL_SECONDS,
    Math.max(MIN_RENEWAL_INTERVAL_SECONDS, visibilityTimeoutSeconds / 5),
  );
}

/**
 * Options for consuming a specific message by ID.
 */
export interface ConsumeByIdOptions {
  /** The specific message ID to consume */
  messageId: string;

  /**
   * Called when the handler throws. Return `{ afterSeconds: N }` to reschedule
   * the message for redelivery after N seconds, or return `undefined`
   * to let the error propagate normally.
   */
  retry?: RetryHandler;
}

/**
 * Options for consuming messages from the queue.
 */
export interface ConsumeBatchOptions {
  /**
   * Maximum number of messages to retrieve in a single request.
   * @default 1
   * @minimum 1
   * @maximum 10
   */
  limit?: number;

  /**
   * Called when the handler throws. Return `{ afterSeconds: N }` to reschedule
   * the message for redelivery after N seconds, or return `undefined`
   * to let the error propagate normally.
   */
  retry?: RetryHandler;
}

/**
 * Options for the consume method. Either consume by message ID or consume
 * from the queue with an optional limit. These options are mutually exclusive.
 */
export type ConsumeOptions = ConsumeByIdOptions | ConsumeBatchOptions;

/**
 * A ConsumerGroup processes messages from a topic with automatic lifecycle management.
 *
 * Features:
 * - Independent message state per group (each group receives a copy of every message)
 * - Automatic visibility timeout extension during processing
 * - Automatic message deletion on successful handler completion
 */
export class ConsumerGroup<T = unknown> {
  private client: ApiClient;
  private topicName: string;
  private consumerGroupName: string;
  private visibilityTimeout: number;

  /**
   * Create a new ConsumerGroup instance.
   *
   * @param client - ApiClient instance to use for API calls (transport is configured on the client)
   * @param topicName - Name of the topic to consume from (pattern: `[A-Za-z0-9_-]+`)
   * @param consumerGroupName - Name of the consumer group (pattern: `[A-Za-z0-9_-]+`)
   * @param options - Optional configuration
   * @param options.visibilityTimeoutSeconds - Message lock duration (default: 300, max: 3600)
   */
  constructor(
    client: ApiClient,
    topicName: string,
    consumerGroupName: string,
    options: ConsumerGroupOptions<T> = {},
  ) {
    this.client = client;
    this.topicName = topicName;
    this.consumerGroupName = consumerGroupName;
    this.visibilityTimeout = Math.max(
      MIN_VISIBILITY_TIMEOUT_SECONDS,
      options.visibilityTimeoutSeconds ?? DEFAULT_VISIBILITY_TIMEOUT_SECONDS,
    );
  }

  /**
   * Check if an error is a 4xx client error that should stop retries.
   * 4xx errors indicate the request is fundamentally invalid and retrying won't help.
   * - 409: Ticket mismatch (lost ownership to another consumer)
   * - 404: Message/receipt handle not found
   * - 400, 401, 403: Other client errors
   */
  private isClientError(error: unknown): boolean {
    return (
      error instanceof MessageNotAvailableError || // 409 - ticket mismatch, lost ownership
      error instanceof MessageNotFoundError || // 404 - receipt handle not found
      error instanceof BadRequestError || // 400 - invalid parameters
      error instanceof UnauthorizedError || // 401 - auth failed
      error instanceof ForbiddenError // 403 - access denied
    );
  }

  /**
   * Starts a background loop that periodically extends the visibility timeout for a message.
   *
   * Timing strategy:
   * - Renewal interval: min(60s, max(10s, visibilityTimeout/5))
   * - Extensions request the same duration as the initial visibility timeout
   * - When `visibilityDeadline` is provided (binary mode small body), the first
   *   extension delay is calculated from the time remaining until the deadline
   *   using the same renewal formula, ensuring the first extension fires before
   *   the server-assigned lease expires. Subsequent renewals use the standard interval.
   *
   * Retry strategy:
   * - On transient failures (5xx, network errors): retry every 3 seconds
   * - On 4xx client errors: stop retrying (the lease is lost or invalid)
   *
   * @param receiptHandle - The receipt handle to extend visibility for
   * @param options - Optional configuration
   * @param options.visibilityDeadline - Absolute deadline (from server's `ce-vqsvisibilitydeadline`)
   *   when the current visibility timeout expires. Used to calculate the first extension delay.
   */
  private startVisibilityExtension(
    receiptHandle: string,
    options?: { visibilityDeadline?: Date },
  ): (waitForCompletion?: boolean) => Promise<void> {
    let isRunning = true;
    let isResolved = false;
    let resolveLifecycle: () => void;
    let timeoutId: NodeJS.Timeout | null = null;

    const renewalIntervalMs =
      calculateRenewalInterval(this.visibilityTimeout) * 1000;

    let firstDelayMs = renewalIntervalMs;
    if (options?.visibilityDeadline) {
      const timeRemainingMs = options.visibilityDeadline.getTime() - Date.now();
      if (timeRemainingMs > 0) {
        const timeRemainingSeconds = timeRemainingMs / 1000;
        firstDelayMs = calculateRenewalInterval(timeRemainingSeconds) * 1000;
      } else {
        firstDelayMs = 0;
      }
    }

    // Promise that tracks the actual termination of the extension loop
    const lifecyclePromise = new Promise<void>((resolve) => {
      resolveLifecycle = resolve;
    });

    const safeResolve = () => {
      if (!isResolved) {
        isResolved = true;
        resolveLifecycle();
      }
    };

    const extend = async (): Promise<void> => {
      // Check if we should stop before attempting extension
      if (!isRunning) {
        safeResolve();
        return;
      }

      try {
        await this.client.changeVisibility({
          queueName: this.topicName,
          consumerGroup: this.consumerGroupName,
          receiptHandle,
          visibilityTimeoutSeconds: this.visibilityTimeout,
        });

        // Successfully extended - schedule next extension
        if (isRunning) {
          timeoutId = setTimeout(() => extend(), renewalIntervalMs);
        } else {
          safeResolve();
        }
      } catch (error) {
        // Check if this is a 4xx client error - stop retrying
        if (this.isClientError(error)) {
          console.error(
            `Visibility extension failed with client error for receipt handle ${receiptHandle} (stopping retries):`,
            error,
          );
          safeResolve();
          return;
        }

        // Transient error - log and schedule retry
        console.error(
          `Failed to extend visibility for receipt handle ${receiptHandle} (will retry in ${RETRY_INTERVAL_MS / 1000}s):`,
          error,
        );

        // Retry after RETRY_INTERVAL_MS if still running
        if (isRunning) {
          timeoutId = setTimeout(() => extend(), RETRY_INTERVAL_MS);
        } else {
          safeResolve();
        }
      }
    };

    timeoutId = setTimeout(() => extend(), firstDelayMs);

    // Return a function to stop the extension loop
    return async (waitForCompletion: boolean = false) => {
      // Signal the loop to stop
      isRunning = false;

      // Cancel any pending timeout to avoid unnecessary waiting
      if (timeoutId) {
        clearTimeout(timeoutId);
        timeoutId = null;
      }

      // Only wait for in-flight operations if explicitly requested
      if (waitForCompletion) {
        // Wait for the loop to actually terminate
        // This ensures any in-progress extension completes or fails
        await lifecyclePromise;
      } else {
        safeResolve();
      }
    };
  }

  /**
   * Clean up the message payload if the transport supports it and payload exists.
   */
  private async finalizePayload<TPayload>(payload: TPayload): Promise<void> {
    const transport = this.client.getTransport();
    if (transport.finalize && payload !== undefined && payload !== null) {
      try {
        await transport.finalize(payload);
      } catch (finalizeError) {
        console.warn("Failed to finalize message payload:", finalizeError);
      }
    }
  }

  private async processMessage<TPayload>(
    message: Message<TPayload>,
    handler: MessageHandler<TPayload>,
    options?: { visibilityDeadline?: Date; retry?: RetryHandler },
  ): Promise<void> {
    const stopExtension = this.startVisibilityExtension(
      message.receiptHandle,
      options,
    );

    const DEFAULT_RETENTION_MS = 86_400_000; // 24 hours
    const metadata: MessageMetadata = {
      messageId: message.messageId,
      deliveryCount: message.deliveryCount,
      createdAt: message.createdAt,
      expiresAt:
        message.expiresAt ??
        new Date(message.createdAt.getTime() + DEFAULT_RETENTION_MS),
      topicName: this.topicName,
      consumerGroup: this.consumerGroupName,
      region: this.client.getRegion(),
    };

    try {
      await handler(message.payload, metadata);
      // Stop extensions immediately - we don't need to wait for in-flight extensions
      // since we're about to acknowledge the message anyway
      await stopExtension();

      await this.client.acknowledgeMessage({
        queueName: this.topicName,
        consumerGroup: this.consumerGroupName,
        receiptHandle: message.receiptHandle,
      });
    } catch (error) {
      // Stop extensions immediately on error - fail fast without waiting
      // for any in-flight extension attempts
      await stopExtension();

      // If a retry handler is configured, give it a chance to reschedule or acknowledge
      if (options?.retry) {
        let directive: RetryDirective | void | undefined;
        try {
          directive = options.retry(error, metadata);
        } catch (retryError) {
          console.warn("retry handler threw:", retryError);
        }

        if (directive) {
          if ("acknowledge" in directive && directive.acknowledge) {
            // Acknowledge the message so it is never retried
            try {
              await this.client.acknowledgeMessage({
                queueName: this.topicName,
                consumerGroup: this.consumerGroupName,
                receiptHandle: message.receiptHandle,
              });
            } catch (ackError) {
              console.warn("Failed to acknowledge message:", ackError);
            }

            await this.finalizePayload(message.payload);
            return;
          }

          if (
            "afterSeconds" in directive &&
            typeof directive.afterSeconds === "number"
          ) {
            try {
              await this.client.changeVisibility({
                queueName: this.topicName,
                consumerGroup: this.consumerGroupName,
                receiptHandle: message.receiptHandle,
                visibilityTimeoutSeconds: directive.afterSeconds,
              });
            } catch (changeError) {
              console.warn(
                "Failed to reschedule message for retry:",
                changeError,
              );
            }

            await this.finalizePayload(message.payload);
            return;
          }
        }
      }

      await this.finalizePayload(message.payload);
      throw error;
    }
  }

  /**
   * Process a pre-fetched message directly, without calling `receiveMessageById`.
   *
   * Used by the binary mode (v2beta) small body fast path, where the server
   * pushes the full message payload in the callback request. The message is
   * processed with the same lifecycle guarantees as `consume()`:
   * - Visibility timeout is extended periodically during processing
   * - Message is acknowledged on successful handler completion
   * - Payload is finalized on error if the transport supports it
   *
   * @param handler - Function to process the message payload and metadata
   * @param message - The complete message including payload and receipt handle
   * @param options - Optional configuration
   * @param options.visibilityDeadline - Absolute deadline when the server-assigned
   *   visibility timeout expires (from `ce-vqsvisibilitydeadline`). Used to
   *   schedule the first visibility extension before the lease expires.
   */
  async consumeMessage(
    handler: MessageHandler<T>,
    message: Message<T>,
    options?: { visibilityDeadline?: Date; retry?: RetryHandler },
  ): Promise<void> {
    await this.processMessage(message, handler, options);
  }

  /**
   * Consume the next available message from the queue.
   *
   * The message is automatically:
   * - Locked with the configured visibility timeout
   * - Kept alive via periodic visibility extensions during processing
   * - Acknowledged upon successful handler completion
   * - Released for retry if the handler throws an error
   *
   * @param handler - Function to process the message payload and metadata.
   *                  Not called when the queue is empty.
   * @returns Number of messages processed (0 if queue was empty)
   * @throws Handler errors are re-thrown after cleanup
   */
  async consume(handler: MessageHandler<T>): Promise<number>;

  /**
   * Consume a specific message by its ID.
   *
   * Used for targeted message processing, typically from webhook callbacks.
   *
   * @param handler - Function to process the message payload and metadata
   * @param options - Options containing the messageId to consume
   * @param options.messageId - Specific message ID to consume
   * @returns Number of messages processed (always 1 on success)
   * @throws {MessageNotFoundError} When message doesn't exist
   * @throws {MessageNotAvailableError} When message in wrong state
   * @throws {MessageAlreadyProcessedError} When already processed
   * @throws Handler errors are re-thrown after cleanup
   */
  async consume(
    handler: MessageHandler<T>,
    options: ConsumeByIdOptions,
  ): Promise<number>;

  /**
   * Consume messages from the queue with an optional batch limit.
   *
   * Fetches up to `limit` messages in a single request and processes them
   * sequentially with the provided handler.
   *
   * @param handler - Function to process each message payload and metadata.
   *                  Not called when the queue is empty.
   * @param options - Options containing the limit
   * @param options.limit - Maximum messages to retrieve (default: 1, min: 1, max: 10)
   * @returns Number of messages processed (0 if queue was empty)
   * @throws Handler errors are re-thrown after cleanup
   */
  async consume(
    handler: MessageHandler<T>,
    options: ConsumeBatchOptions,
  ): Promise<number>;

  async consume(
    handler: MessageHandler<T>,
    options?: ConsumeOptions,
  ): Promise<number> {
    const retry = options?.retry;

    if (options && "messageId" in options) {
      const response = await this.client.receiveMessageById<T>({
        queueName: this.topicName,
        consumerGroup: this.consumerGroupName,
        messageId: options.messageId,
        visibilityTimeoutSeconds: this.visibilityTimeout,
      });
      await this.processMessage<T>(response.message, handler, { retry });
      return 1;
    } else {
      const limit = options && "limit" in options ? options.limit : 1;
      let messagesProcessed = 0;

      for await (const message of this.client.receiveMessages<T>({
        queueName: this.topicName,
        consumerGroup: this.consumerGroupName,
        visibilityTimeoutSeconds: this.visibilityTimeout,
        limit,
      })) {
        messagesProcessed++;
        await this.processMessage<T>(message, handler, { retry });
      }

      return messagesProcessed;
    }
  }

  /**
   * Get the consumer group name
   */
  get name(): string {
    return this.consumerGroupName;
  }

  /**
   * Get the topic name this consumer group is subscribed to
   */
  get topic(): string {
    return this.topicName;
  }
}
